var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"......그렇군요. 상황은 이해했습니다.","JPN":"……そうですか。状況は理解しました。","ENG":"... I see. I understand the situation.","TWN":"……原來如此，情況我已經瞭解了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그러게 내가 말했잖아. 처음부터 그 녀석이 의심스러웠다니까?","JPN":"だから言ったじゃない。最初からあいつが怪しいって！","ENG":"I told you. He's been suspicious since the beginning!","TWN":"我剛開始就說過，那個傢伙非常可疑！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"아직 주시윤 님이 범인이라고 확정된 것은 아닙니다.","JPN":"まだアキヤマ・シリュウさんが犯人だと決まったわけではありません。","ENG":"We still don't know if Mr. Shiyoon is the perpetrator.","TWN":"但現在還不能斷定周時雲就是兇手。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"다른 이유가 있어서 싸운 것일 수도 있지 않나요?","JPN":"他の理由があって、戦っているということもありますから。","ENG":"It's also possible that he fought you for a different reason.","TWN":"說不定他有其他緣由才會這麼做。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"하지만 유력한 용의자인 건 사실이죠.","JPN":"しかし、有力な容疑者であるのも事実です。","ENG":"Still, he's the most likely suspect.","TWN":"但他確實是最大的嫌疑人。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"방금 전에도 무장 해제를 거부하고 도망쳤잖아요?","JPN":"さっきも武装解除を拒否して逃げたじゃないですか。","ENG":"Even now, he refused to disarm and ran away.","TWN":"妳都看到他剛剛拒絕解除武裝，然後就跑了！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"무슨 말씀인지는 이해했습니다.","JPN":"何をおっしゃりたいのかは理解しました。","ENG":"I understand.","TWN":"我明白妳的意思。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"하지만 주시윤 님이 이런 짓을 저지를 만한 분이라면, 주인님께서 가까이 두셨을지 의문이군요.","JPN":"しかし、アキヤマ様がこのようなことをするお方でしたら、ご主人様が傍に置くでしょうか？","ENG":"But I doubt the Master would have kept Mr. Shiyoon so close if he was such a heinous man.","TWN":"但如果周時雲真是那樣的人，主人是不會和他走這麼近的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"끄응...... 주인님만 붙이면 만사 해결이라 속 편하겠어, 참.","JPN":"うっ……ご主人様を持ち出せば何でも解決できちゃうんだからいいもんよね。","ENG":"Gah, again with the Master!","TWN":"唉……一句主人就解決了所有事，真是輕鬆。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그러면 베로니카 씨는 선배를 의심하지 않는 건가요?","JPN":"そしたら、ベロニカさんは先輩が怪しくないと言うのですか？","ENG":"Then, Veronica, don't you think he's the one?","TWN":"所以貝洛妮卡妳並不認為前輩是兇手？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"많은 용의점이 있지만, 범인으로 단정 짓기 전에 확인은 필요하다고 봅니다. ","JPN":"怪しい点は多いですが、犯人として断定する前に確認が必要だと思います。 ","ENG":"He's definitely suspicious, but I still think we should check before making any conclusion. ","TWN":"雖然有很多疑點，但在斷定他為兇手之前，還需要再確認一下。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"최선의 방법은 본인을 찾아 직접 이야기를 듣는 것이겠죠.","JPN":"最善の策としては、本人から直接話を聞くことでしょう。","ENG":"The best way would be to find and talk to him.","TWN":"最好的辦法，就是找到他，聽他解釋。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"모네도 최선을 다해 돕겠슴다!","JPN":"モネも最善を尽くすっすよ！","ENG":"Mone will help as best as I can, ma'am!","TWN":"莫妮會竭盡全力幫您的！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"그런데 시윤님은 어디로 가신 검까?","JPN":"しかし、アキヤマ様はどこに行ったっすか？","ENG":"By the way, where did he go, ma'am?","TWN":"可是時雲大人到底去哪裡了？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그걸 알면 내가 가만 있겠어? 당장 미사일을 떨어뜨렸지.","JPN":"それがわかれば、こんなところでじっとしてると思う？　すぐにでもミサイルを撃ち込むわ。","ENG":"If I knew, I would have already dropped a missile on him.","TWN":"要是我知道他去哪裡了，還會放過他嗎？我恨不得馬上射個導彈。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"신중한 사람이니까 이렇게 여러 명이 모여 있을 때 무턱대고 공격하진 않을 거예요.","JPN":"慎重な人ですから、このようにみんなで集まっているときに、攻撃してくることはないでしょう。","ENG":"He's careful. He won't attack us when we're together like this.","TWN":"他是一個很慎重的人，這麼多人聚在一起，他是絕對不會貿然攻擊的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"선배를 범인이라고 가정하면, 최대한 효율적으로 희생자를 만들 수 있게 움직이겠죠.","JPN":"先輩を犯人だと仮定すると、できるだけ効率的に犠牲者を作れるよう動くはずです。","ENG":"If he really is the perpetrator, he'll move in such a way that he can take care of us most effectively.","TWN":"如果前輩真的是兇手，肯定會以最大效率造出受害者。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"아하! 혼자 있는 사람들부터 습격한다는 말씀임까?","JPN":"なるほど！　一人でいる人から襲ってくるということっすか？","ENG":"Aha! You mean he'll first attack those who are alone, ma'am?","TWN":"啊哈！您是說他首先會襲擊落單的人嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"그럼 지금 혼자 계신 분이......","JPN":"ということは、今一人でいる方は……","ENG":"Then, who's alone now—","TWN":"現在落單的人……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"......그러고 보니 그 분은 어디 있죠?","JPN":"そういえば……あの方は今どちらに？","ENG":"Speaking of which, where is she?","TWN":"……對了，那位去哪裡了？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"그 분이라면?","JPN":"あの方とは？","ENG":"Who?","TWN":"那位？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"이번 행사에 장식용 조각상을 제공했다는 사장님의 친구 분이요.","JPN":"このパーティーに彫刻像を提供したという社長のご友人です。","ENG":"The Boss's friend who provided the exhibitory sculptures for this event.","TWN":"就是提供了展示用雕像的老闆的朋友。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"이름이...... 알렉스라고 했었나?","JPN":"確か名前が……アレックスだったような。","ENG":"I think her name was... Alex.","TWN":"她好像叫……雅蕾克絲？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"알렉스 님 말씀이시군요. 갑작스럽게 나타나셔서 기억하고 있었습니다.","JPN":"アレックス様ですね。突然現れたのでよく覚えています。","ENG":"You mean, Ms. Alex. I remember her because she showed up all of a sudden.","TWN":"原來您是說雅蕾克絲小姐，她出現的很突然，倒是讓我記住了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"그 분이라면 지금쯤 응접실에서 한소림 님과 함께......","JPN":"その方なら、応接室でハネダ・ミズキ様と一緒に……","ENG":"She must be in the reception room with Ms. Sorim—","TWN":"那位現在估計應該在會客廳和韓蕭林小姐一起……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"......!!","JPN":"……！？","ENG":"......!!","TWN":"……！！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"둘뿐이라고요? 왜 같이 오지 않은 거죠?","JPN":"二人だけですか？　どうして一緒に来なかったんですか？","ENG":"Just the two of them? Why didn't you come with them?","TWN":"就只有她們兩個人嗎？怎麼沒一起過來？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"전투가 벌어졌다고 판단했기 때문입니다.","JPN":"戦闘が起こったと判断したからです。","ENG":"Because I sensed that there was combat.","TWN":"因為我認為發生了戰鬥。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"손님을 위험한 장소에 모시고 갈 순 없으니까요.","JPN":"お客様を危険な場所にお連れすることはできないので。","ENG":"I couldn't risk exposing the guests to such danger.","TWN":"總不能帶著客人來到危險的地方。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"당장 가죠! 어쩌면 선배가 먼저......!","JPN":"今すぐ行きましょう！　もしかしたら、先輩が先に……！","ENG":"Let's go! Shiyoon could be there already—","TWN":"快走吧！說不定前輩已經……！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"꺄아아악!!","JPN":"キャアアッ！","ENG":"Kyaaaaaakkk!","TWN":"呀啊啊阿！！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"이 비명 소리는......?! 안 돼!","JPN":"この悲鳴は……！？　まさか！","ENG":"Screams? Oh, no!","TWN":"這個尖叫……？！不要！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};